  const currentHash = simpleHash(serializedValue);
  if (globals.lastHashes[key] === currentHash) {
    log("info", `[Utils] [Redis] \u952E ${key} \u65E0\u53D8\u5316\uFF0C\u8DF3\u8FC7 SET \u8BF7\u6C42`);
    return { result: "OK" };
  }
